1. using System.Text.Json.Nodes;
2. using System.Text.Json.Serialization;
3. using SkillValidator.Shared;
4. 
5. namespace SkillValidator.Evaluate;
6. 
7. // --- Failure classification ---
8. 
9. [JsonConverter(typeof(JsonStringEnumConverter<FailureKind>))]
10. public enum FailureKind
11. {
12.     [JsonStringEnumMemberName("no_scenarios")]
13.     NoScenarios,
14. 
15.     [JsonStringEnumMemberName("completion_regression")]
16.     CompletionRegression,
17. 
18.     [JsonStringEnumMemberName("threshold")]
19.     Threshold,
20. 
21.     [JsonStringEnumMemberName("spec_conformance_failure")]
22.     SpecConformanceFailure,
23. 
24.     [JsonStringEnumMemberName("skill_not_activated")]
25.     SkillNotActivated,
26. 
27.     [JsonStringEnumMemberName("noise_degradation")]
28.     NoiseDegradation,
29. }
30. 
31. // --- Assertion types ---
32. 
33. public enum AssertionType
34. {
35.     FileExists,
36.     FileNotExists,
37.     FileContains,
38.     FileNotContains,
39.     OutputContains,
40.     OutputNotContains,
41.     OutputMatches,
42.     OutputNotMatches,
43.     ExitSuccess,
44.     RunCommandAndAssert,
45.     ExpectTools,
46.     RejectTools,
47.     MaxTurns,
48.     MaxTokens,
49. }
50. 
51. public sealed record CommandAssertionArgs(
52.     string CommandToRun,
53.     string? CommandArguments = null,
54.     int? ExpectedExitCode = null,
55.     string? ExpectedStdOutContains = null,
56.     string? ExpectedStdErrorContains = null,
57.     string? ExpectedStdOutMatches = null,
58.     string? ExpectedStdErrorMatches = null,
59.     int? Timeout = null);
60. 
61. public sealed record Assertion(
62.     AssertionType Type,
63.     string? Path = null,
64.     string? Value = null,
65.     string? Pattern = null,
66.     CommandAssertionArgs? CommandArgs = null);
67. 
68. public sealed record AssertionResult(
69.     Assertion Assertion,
70.     bool Passed,
71.     string Message);
72. 
73. // --- Setup ---
74. 
75. public sealed record SetupFile(
76.     string Path,
77.     string? Source = null,
78.     string? Content = null);
79. 
80. public sealed record SetupConfig(
81.     bool CopyTestFiles = false,
82.     IReadOnlyList<SetupFile>? Files = null,
83.     IReadOnlyList<string>? Commands = null,
84.     IReadOnlyList<string>? AdditionalRequiredSkills = null,
85.     IReadOnlyList<string>? AdditionalRequiredAgents = null);
86. 
87. // --- Scenario ---
88. 
89. public sealed record EvalScenario(
90.     string Name,
91.     string Prompt,
92.     SetupConfig? Setup = null,
93.     IReadOnlyList<Assertion>? Assertions = null,
94.     IReadOnlyList<string>? Rubric = null,
95.     int Timeout = EvalSchema.DefaultScenarioTimeoutSeconds,
96.     IReadOnlyList<string>? ExpectTools = null,
97.     IReadOnlyList<string>? RejectTools = null,
98.     int? MaxTurns = null,
99.     int? MaxTokens = null,
100.     bool ExpectActivation = true);
101. 
102. public sealed record EvalConfig(
103.     IReadOnlyList<EvalScenario> Scenarios,
104.     int? MaxParallelScenarios = null,
105.     int? MaxParallelRuns = null);
106. 
107. /// <summary>
108. /// Extends SkillInfo with evaluation-specific data (eval.yaml config, MCP servers).
109. /// Used only by the eval command and its supporting services.
110. /// </summary>
111. public sealed record EvalSkillInfo(
112.     SkillInfo Skill,
113.     string? EvalPath,
114.     EvalConfig? EvalConfig,
115.     IReadOnlyDictionary<string, MCPServerDef>? McpServers = null);
116. 
117. /// <summary>
118. /// Unified eval target — either a skill or an agent.
119. /// Most of the evaluation pipeline operates on this generically.
120. /// </summary>
121. public enum EvalTargetKind { Skill, Agent }
122. 
123. public sealed record EvalTargetInfo(
124.     string Name,
125.     string Path,
126.     EvalTargetKind Kind,
127.     SkillInfo? Skill,
128.     AgentInfo? Agent,
129.     string? EvalPath,
130.     EvalConfig? EvalConfig,
131.     string? PluginRoot,
132.     IReadOnlyDictionary<string, MCPServerDef>? McpServers);
133. 
134. // --- Agent events ---
135. 
136. public sealed record AgentEvent(
137.     string Type,
138.     long Timestamp,
139.     Dictionary<string, JsonNode?> Data);
140. 
141. // --- Judge results ---
142. 
143. public sealed record RubricScore(
144.     string Criterion,
145.     double Score,
146.     string Reasoning);
147. 
148. public sealed record JudgeResult(
149.     IReadOnlyList<RubricScore> RubricScores,
150.     double OverallScore,
151.     string OverallReasoning);
152. 
153. /// <summary>Lightweight token counter returned by judge helpers.</summary>
154. public sealed record TokenUsage(int InputTokens, int OutputTokens, int CacheReadTokens, int CacheWriteTokens)
155. {
156.     public static TokenUsage Zero { get; } = new(0, 0, 0, 0);
157. 
158.     public static TokenUsage operator +(TokenUsage a, TokenUsage b) =>
159.         new(a.InputTokens + b.InputTokens,
160.             a.OutputTokens + b.OutputTokens,
161.             a.CacheReadTokens + b.CacheReadTokens,
162.             a.CacheWriteTokens + b.CacheWriteTokens);
163. }
164. 
165. // --- Run metrics ---
166. 
167. public sealed class RunMetrics
168. {
169.     public int TokenEstimate { get; set; }
170.     public int InputTokens { get; set; }
171.     public int OutputTokens { get; set; }
172.     public int CacheReadTokens { get; set; }
173.     public int CacheWriteTokens { get; set; }
174.     public int JudgeInputTokens { get; set; }
175.     public int JudgeOutputTokens { get; set; }
176.     public int JudgeCacheReadTokens { get; set; }
177.     public int JudgeCacheWriteTokens { get; set; }
178.     public int ToolCallCount { get; set; }
179.     public Dictionary<string, int> ToolCallBreakdown { get; set; } = new();
180.     public int TurnCount { get; set; }
181.     public long WallTimeMs { get; set; }
182.     public int ErrorCount { get; set; }
183.     public bool TimedOut { get; set; }
184.     public List<AssertionResult> AssertionResults { get; set; } = [];
185.     public bool TaskCompleted { get; set; }
186.     public string AgentOutput { get; set; } = "";
187.     public List<AgentEvent> Events { get; set; } = [];
188.     public string WorkDir { get; set; } = "";
189. }
190. 
191. public sealed record RunResult(
192.     RunMetrics Metrics,
193.     JudgeResult JudgeResult);
194. 
195. // --- Pairwise judging ---
196. 
197. public enum PairwiseMagnitude
198. {
199.     MuchBetter,
200.     SlightlyBetter,
201.     Equal,
202.     SlightlyWorse,
203.     MuchWorse,
204. }
205. 
206. public sealed record PairwiseRubricResult(
207.     string Criterion,
208.     string Winner, // "baseline" | "skill" | "tie"
209.     PairwiseMagnitude Magnitude,
210.     string Reasoning);
211. 
212. public sealed record PairwiseJudgeResult(
213.     IReadOnlyList<PairwiseRubricResult> RubricResults,
214.     string OverallWinner, // "baseline" | "skill" | "tie"
215.     PairwiseMagnitude OverallMagnitude,
216.     string OverallReasoning,
217.     bool PositionSwapConsistent);
218. 
219. public static class PairwiseMagnitudeScores
220. {
221.     public static double GetScore(PairwiseMagnitude magnitude) => magnitude switch
222.     {
223.         PairwiseMagnitude.MuchBetter => 1.0,
224.         PairwiseMagnitude.SlightlyBetter => 0.4,
225.         PairwiseMagnitude.Equal => 0.0,
226.         PairwiseMagnitude.SlightlyWorse => -0.4,
227.         PairwiseMagnitude.MuchWorse => -1.0,
228.         _ => 0.0,
229.     };
230. }
231. 
232. public enum JudgeMode
233. {
234.     Pairwise,
235.     Independent,
236.     Both,
237. }
238. 
239. // --- Skill activation ---
240. 
241. public sealed record SkillActivationInfo(
242.     bool Activated,
243.     IReadOnlyList<string> DetectedSkills,
244.     IReadOnlyList<string> ExtraTools,
245.     int SkillEventCount);
246. 
247. // --- Subagent (custom agent) activation ---
248. 
249. public sealed record SubagentActivationInfo(
250.     IReadOnlyList<string> InvokedAgents,
251.     int SubagentEventCount);
252. 
253. // --- Comparison ---
254. 
255. public sealed record MetricBreakdown(
256.     double TokenReduction,
257.     double ToolCallReduction,
258.     double TaskCompletionImprovement,
259.     double TimeReduction,
260.     double QualityImprovement,
261.     double OverallJudgmentImprovement,
262.     double ErrorReduction);
263. 
264. public sealed record ConfidenceInterval(
265.     double Low,
266.     double High,
267.     double Level);
268. 
269. public sealed class ScenarioComparison
270. {
271.     public required string ScenarioName { get; init; }
272.     public required RunResult Baseline { get; init; }
273.     public RunResult SkilledIsolated { get; init; } = null!;
274.     public RunResult? SkilledPlugin { get; init; }
275.     public required double ImprovementScore { get; init; }
276.     public double IsolatedImprovementScore { get; init; }
277.     public double PluginImprovementScore { get; init; }
278.     public required MetricBreakdown Breakdown { get; init; }
279.     public MetricBreakdown? IsolatedBreakdown { get; init; }
280.     public MetricBreakdown? PluginBreakdown { get; init; }
281.     public PairwiseJudgeResult? PairwiseResult { get; init; }
282.     public IReadOnlyList<double>? PerRunScores { get; set; }
283.     /// <summary>True when the coefficient of variation across runs exceeds the high-variance threshold.</summary>
284.     public bool HighVariance { get; set; }
285.     /// <summary>Coefficient of variation across per-run scores. Null when fewer than 2 runs.</summary>
286.     public double? VarianceCV { get; set; }
287.     public SkillActivationInfo? SkillActivationIsolated { get; set; }
288.     public SkillActivationInfo? SkillActivationPlugin { get; set; }
289.     public SubagentActivationInfo? SubagentActivationIsolated { get; set; }
290.     public SubagentActivationInfo? SubagentActivationPlugin { get; set; }
291.     public bool TimedOut { get; set; }
292.     /// <summary>The scenario timeout in seconds, if known (e.g., from eval.yaml or persisted session data).</summary>
293.     public int? TimeoutSeconds { get; set; }
294.     /// <summary>When false, non-activation is expected (negative test) and should not flag the verdict.</summary>
295.     public bool ExpectActivation { get; set; } = true;
296. 
297.     // Backward-compatible aliases for JSON deserialization of older results files.
298.     [JsonPropertyName("withSkill")]
299.     public RunResult WithSkill { get => SkilledIsolated; init => SkilledIsolated = value; }
300.     [JsonPropertyName("skillActivation")]
301.     public SkillActivationInfo? SkillActivation { get => SkillActivationIsolated; init => SkillActivationIsolated = value; }
302. }
303. 
304. // --- Verdict ---
305. 
306. public sealed class SkillVerdict
307. {
308.     public required string SkillName { get; init; }
309.     public required string SkillPath { get; init; }
310.     public required bool Passed { get; set; }
311.     public required IReadOnlyList<ScenarioComparison> Scenarios { get; init; }
312.     public required double OverallImprovementScore { get; init; }
313.     public double? NormalizedGain { get; init; }
314.     public ConfidenceInterval? ConfidenceInterval { get; init; }
315.     public bool? IsSignificant { get; init; }
316.     public double? IsolatedScore { get; set; }
317.     public double? PluginScore { get; set; }
318.     public required string Reason { get; set; }
319.     /// <summary>Categorizes why the verdict failed, if it did.</summary>
320.     public FailureKind? FailureKind { get; set; }
321.     public bool SkillNotActivated { get; set; }
322.     public OverfittingResult? OverfittingResult { get; set; }
323.     public NoiseTestResult? NoiseTestResult { get; set; }
324. }
325. 
326. // --- Overfitting assessment ---
327. 
328. [JsonConverter(typeof(JsonStringEnumConverter<OverfittingSeverity>))]
329. public enum OverfittingSeverity
330. {
331.     Low,
332.     Moderate,
333.     High,
334. }
335. 
336. public sealed record RubricOverfitAssessment(
337.     string Scenario,
338.     string Criterion,
339.     string Classification,      // "outcome" | "technique" | "vocabulary"
340.     double Confidence,
341.     string Reasoning);
342. 
343. public sealed record AssertionOverfitAssessment(
344.     string Scenario,
345.     string AssertionSummary,
346.     string Classification,      // "broad" | "narrow"
347.     double Confidence,
348.     string Reasoning);
349. 
350. public sealed record PromptOverfitAssessment(
351.     string Scenario,
352.     string Issue,               // e.g. "explicit_skill_reference" | "skill_instruction"
353.     double Confidence,
354.     string Reasoning);
355. 
356. public sealed record OverfittingResult(
357.     double Score,               // [0, 1]
358.     OverfittingSeverity Severity,
359.     IReadOnlyList<RubricOverfitAssessment> RubricAssessments,
360.     IReadOnlyList<AssertionOverfitAssessment> AssertionAssessments,
361.     IReadOnlyList<PromptOverfitAssessment> PromptAssessments,
362.     IReadOnlyList<string> CrossScenarioIssues,
363.     string OverallReasoning);
364. 
365. public sealed record OverfittingJudgeOptions(
366.     string Model,
367.     bool Verbose,
368.     int Timeout,
369.     string WorkDir);
370. 
371. // --- Multi-skill noise test ---
372. 
373. public sealed record NoiseScenarioResult(
374.     string ScenarioName,
375.     RunResult WithSkillOnly,
376.     RunResult WithAllSkills,
377.     double DegradationScore,
378.     MetricBreakdown Breakdown,
379.     SkillActivationInfo? SkillActivation,
380.     int TotalSkillsLoaded);
381. 
382. public sealed record NoiseTestResult(
383.     IReadOnlyList<NoiseScenarioResult> Scenarios,
384.     double OverallDegradation,
385.     bool Passed,
386.     string Reason,
387.     int TotalSkillsLoaded);
388. 
389. // --- Eval config ---
390. 
391. public sealed record ReporterSpec(ReporterType Type);
392. 
393. public enum ReporterType
394. {
395.     Console,
396.     Json,
397.     Junit,
398.     Markdown,
399. }
400. 
401. public sealed record ValidatorConfig
402. {
403.     public double MinImprovement { get; init; } = 0.1;
404.     public bool RequireCompletion { get; init; } = true;
405.     public bool Verbose { get; init; }
406.     public string Model { get; init; } = "claude-opus-4.6";
407.     public string JudgeModel { get; init; } = "claude-opus-4.6";
408.     public JudgeMode JudgeMode { get; init; } = JudgeMode.Pairwise;
409.     public int Runs { get; init; } = 5;
410.     public int ParallelSkills { get; init; } = 1;
411.     public int ParallelScenarios { get; init; } = 1;
412.     public int ParallelRuns { get; init; } = 1;
413.     public int JudgeTimeout { get; init; } = 300_000;
414.     public double ConfidenceLevel { get; init; } = 0.95;
415.     public IReadOnlyList<ReporterSpec> Reporters { get; init; } = [];
416.     public IReadOnlyList<string> SkillPaths { get; init; } = [];
417.     public bool VerdictWarnOnly { get; init; }
418.     public string? ResultsDir { get; init; }
419.     public string? TestsDir { get; init; }
420.     public bool OverfittingCheck { get; init; } = true;
421.     public bool OverfittingFix { get; init; }
422.     public bool KeepSessions { get; init; }
423.     public string? NoiseSkillsDir { get; init; }
424.     public double NoiseDegradationLimit { get; init; } = 0.2;
425.     public double NoiseMaxScenarioDegradation { get; init; } = 0.4;
426. }
427. 
428. public static class DefaultWeights
429. {
430.     public static readonly IReadOnlyDictionary<string, double> Values = new Dictionary<string, double>
431.     {
432.         ["TokenReduction"] = 0.05,
433.         ["ToolCallReduction"] = 0.025,
434.         ["TaskCompletionImprovement"] = 0.15,
435.         ["TimeReduction"] = 0.025,
436.         ["QualityImprovement"] = 0.40,
437.         ["OverallJudgmentImprovement"] = 0.30,
438.         ["ErrorReduction"] = 0.05,
439.     };
440. }
441. 
442. // --- JSON transport types ---
443. 
444. internal sealed class ConsolidateData
445. {
446.     public string? Model { get; set; }
447.     public string? JudgeModel { get; set; }
448.     public List<SkillVerdict>? Verdicts { get; set; }
449. }
450. 
451. internal sealed class ResultsOutput
452. {
453.     public required string Model { get; init; }
454.     public required string JudgeModel { get; init; }
455.     public required string Timestamp { get; init; }
456.     public required IReadOnlyList<SkillVerdict> Verdicts { get; init; }
457. }
458.

